def generate_compliance_reports(apps, schema_editor):
    _TARGET_REPORTING_YEAR = 2024
    _REGULATED_OPERATION_PURPOSES = ['OBPS Regulated Operation', 'New Entrant Operation', 'Opted-in Operation']

    if settings.ENVIRONMENT != 'prod':
        logger.info("Skipping compliance report generation migration")
        return
    from compliance.service.compliance_report_version_service import ComplianceReportVersionService

    ReportVersion = apps.get_model('reporting', 'ReportVersion')
    ComplianceReport = apps.get_model('compliance', 'ComplianceReport')
    CompliancePeriod = apps.get_model('compliance', 'CompliancePeriod')
    for rv in ReportVersion.objects.select_related('report', 'report_operation').filter(
        report__reporting_year_id=_TARGET_REPORTING_YEAR,
        report_operation__registration_purpose__in=_REGULATED_OPERATION_PURPOSES,
        is_latest_submitted=True,
    ):
        if ComplianceReport.objects.filter(report_id=rv.report_id).exists():
            continue
        with transaction.atomic():
            new_report = ComplianceReport.objects.create(
                report=rv.report,
                compliance_period=CompliancePeriod.objects.get(reporting_year=_TARGET_REPORTING_YEAR),
            )
            ComplianceReportVersionService.create_compliance_report_version(new_report.id, rv.id)


def reverse_generate_compliance_reports(apps, schema_editor):
    apps.get_model('compliance', 'ComplianceReport').objects.all().delete()


